// HELPER: Find User by Referral Code (for commission logic)
const findUserByReferralCode = async (code: string) => {
  // Try direct lookup first
  const codeSnap = await getDoc(doc(db, 'referral_codes', code));
  if (codeSnap.exists()) {
      const userId = codeSnap.data().userId;
      const userSnap = await getDoc(doc(db, 'users', userId));
      if (userSnap.exists()) {
          return { ref: userSnap.ref, data: userSnap.data() as User };
      }
  }

  // Fallback to query
  const q = query(collection(db, 'users'), where('referralCode', '==', code), limit(1));
  const snap = await getDocs(q);
  if (snap.empty) return null;
  return { ref: snap.docs[0].ref, data: snap.docs[0].data() as User };
};

export const purchasePackageFirestore = async (userId: string, pkgId: string, currentPackages: Package[]) => {
  const pkg = currentPackages.find(p => p.id === pkgId);
  if (!pkg) throw new Error("Invalid Package Configuration");

  // 1. Resolve Upline BEFORE transaction (to handle complex queries outside transaction)
  const userRef = doc(db, 'users', userId);
  const userSnapBefore = await getDoc(userRef);
  if(!userSnapBefore.exists()) throw new Error("User not found");
  const userDataBefore = userSnapBefore.data() as User;

  const uplineRefs: { ref: any, percentage: number, level: number }[] = [];
  let currentReferrerCode = userDataBefore.referredBy;

  // Resolve 3 Levels Deep
  for (const levelConfig of REF_LEVELS) {
      if (!currentReferrerCode) break;
      const uplineUser = await findUserByReferralCode(currentReferrerCode);
      if (uplineUser) {
          uplineRefs.push({ 
              ref: uplineUser.ref, 
              percentage: levelConfig.percentage, 
              level: levelConfig.level 
          });
          currentReferrerCode = uplineUser.data.referredBy;
      } else {
          break;
      }
  }

  const activePkgsQuery = query(collection(db, 'activePackages'), where('userId', '==', userId), where('isActive', '==', true));
  const activePkgsSnap = await getDocs(activePkgsQuery);
  const existingDocRef = activePkgsSnap.empty ? null : activePkgsSnap.docs[0].ref;
  let cost = pkg.minAmount;

  // 2. Execute MAIN Purchase Transaction (User focused only)
  // We intentionally separate the referral commission logic to prevent the user's purchase 
  // from failing if there are permission issues updating the referrer's account.
  await runTransaction(db, async (transaction) => {
    const userSnap = await transaction.get(userRef);
    if (!userSnap.exists()) throw new Error("User does not exist!");
    const userData = userSnap.data() as User;

    let isUpgrade = false;
    let currentData: UserPackage | null = null;

    if (existingDocRef) {
      const pkgSnap = await transaction.get(existingDocRef);
      if (pkgSnap.exists()) {
        currentData = pkgSnap.data() as UserPackage;
        if (currentData.packageId === pkgId) throw new Error("Plan already active.");
        if (pkg.minAmount <= currentData.amount) throw new Error("Downgrade not allowed.");
        cost = pkg.minAmount - currentData.amount;
        isUpgrade = true;
      }
    }

    if (userData.capitalBalance < cost) throw new Error(`Insufficient balance. Required: ${cost.toFixed(2)} USDT`);

    // Deduct Cost
    transaction.update(userRef, { capitalBalance: increment(-cost) });

    // Update/Create Package
    if (isUpgrade && existingDocRef && currentData) {
      transaction.update(existingDocRef, { packageId: pkg.id, amount: pkg.minAmount, activatedAt: Date.now(), lastPayoutAt: Date.now() });
    } else {
      const activePkgRef = doc(collection(db, 'activePackages'));
      transaction.set(activePkgRef, { id: activePkgRef.id, packageId: pkg.id, amount: pkg.minAmount, activatedAt: Date.now(), lastPayoutAt: Date.now(), isActive: true, totalEarned: 0, userId });
    }

    // Create Transaction
    const txRef = doc(collection(db, 'transactions'));
    transaction.set(txRef, { id: txRef.id, userId, type: TransactionType.PURCHASE, amount: cost, status: TransactionStatus.COMPLETED, timestamp: Date.now(), description: isUpgrade ? `Upgrade to ${pkg.name}` : `Node Activation: ${pkg.name}` });
  });

  // 3. Process Referral Commissions (Best Effort)
  // Wrapped in try/catch so it doesn't revert the purchase if it fails.
  if (uplineRefs.length > 0) {
      try {
          await runTransaction(db, async (transaction) => {
            for (const upline of uplineRefs) {
                const upSnap = await transaction.get(upline.ref);
                if (upSnap.exists()) {
                    const commission = cost * (upline.percentage / 100);
                    if (commission > 0) {
                        transaction.update(upline.ref, {
                            profitBalance: increment(commission),
                            referralEarnings: increment(commission),
                            totalEarned: increment(commission)
                        });

                        // Try to write the transaction record for the referrer
                        // This might fail if users can't create docs for others, 
                        // but since we are inside a try/catch block outside the main purchase, it's safer.
                        const refTxRef = doc(collection(db, 'transactions'));
                        transaction.set(refTxRef, {
                            id: refTxRef.id,
                            userId: upSnap.id,
                            type: TransactionType.REFERRAL,
                            amount: commission,
                            status: TransactionStatus.COMPLETED,
                            timestamp: Date.now(),
                            description: `L${upline.level} Commission (${upline.percentage}%) from ${userDataBefore.email}`
                        });
                    }
                }
            }
          });
      } catch (err) {
          console.warn("Commission processing skipped due to permissions/error:", err);
      }
  }
};

export const processDailyRoiFirestore = async (settings: any, currentPackages: Package[]) => {
  if (!settings.isRoiEnabled || settings.platformPaused) return;
  const activePkgsQuery = query(collection(db, 'activePackages'), where('isActive', '==', true));
  const activePkgsSnap = await getDocs(activePkgsQuery);
  const now = Date.now();
  const ONE_DAY_MS = 24 * 60 * 60 * 1000;
  for (const docSnap of activePkgsSnap.docs) {
    const ap = docSnap.data() as UserPackage;
    const pkg = currentPackages.find(p => p.id === ap.packageId);
    if (!pkg || pkg.isActive === false) continue;
    const lastPayout = ap.lastPayoutAt || ap.activatedAt;
    if (now - lastPayout < ONE_DAY_MS) continue;
    const dailyPercent = settings.roiOverride || pkg.dailyRoi;
    const earnings = ap.amount * (dailyPercent / 100);
    await runTransaction(db, async (transaction) => {
      const userRef = doc(db, 'users', ap.userId);
      transaction.update(userRef, { profitBalance: increment(earnings), totalEarned: increment(earnings) });
      transaction.update(doc(db, 'activePackages', docSnap.id), { totalEarned: increment(earnings), lastPayoutAt: now });
      const txRef = doc(collection(db, 'transactions'));
      transaction.set(txRef, { id: txRef.id, userId: ap.userId, type: TransactionType.ROI, amount: earnings, status: TransactionStatus.COMPLETED, timestamp: now, description: `Daily profit from ${pkg.name}` });
    });
  }
};

