// Updated sanitization logic to handle Firestore refs without crashing
const sanitizeDoc = (docSnap: any) => {
    const data = docSnap.data();
    const clean: any = { id: docSnap.id };

    if (!data) return clean;

    Object.keys(data).forEach(key => {
        const val = data[key];
        if (val && typeof val === 'object') {
            if (typeof val.toMillis === 'function') {
                clean[key] = val.toMillis();
            } else if (val.path && typeof val.path === 'string') {
                clean[key] = val.path;
            } else if (Array.isArray(val)) {
                clean[key] = val;
            } else {
                // If it's a plain object, we copy it. If it's a complex Firestore object, we skip deep copy to avoid circular errors
                if (val.constructor === Object) {
                    clean[key] = { ...val };
                } else {
                    // Safe fallback for internal/complex objects
                    clean[key] = null;
                }
            }
        } else {
            clean[key] = val;
        }
    });
    return clean;
};

