// Updated sanitization logic to match App.tsx and prevent circular JSON errors
const sanitizeDoc = (docSnap: any) => {
    const data = docSnap.data();
    if (!data) return { id: docSnap.id };

    const clean: any = { id: docSnap.id };

    Object.keys(data).forEach(key => {
        const val = data[key];

        // 1. Handle Timestamp (convert to millis)
        if (val && typeof val.toMillis === 'function') {
            clean[key] = val.toMillis();
        }
        // 2. Handle DocumentReference (convert to path string)
        else if (val && val.path && typeof val.path === 'string' && (val.type === 'document' || val.constructor.name === 'DocumentReference')) {
             clean[key] = val.path;
        }
        // 3. Handle Arrays (recurse gently)
        else if (Array.isArray(val)) {
            clean[key] = val.map((item: any) => {
                if (item && typeof item.toMillis === 'function') return item.toMillis();
                if (item && item.path) return item.path;
                return item;
            });
        }
        // 4. Handle Objects (shallow copy only plain objects, ignore complex ones)
        else if (val && typeof val === 'object') {
             try {
                 // Check if it's a plain object
                 if (Object.prototype.toString.call(val) === '[object Object]') {
                     clean[key] = { ...val };
                 } else {
                     // If it's a complex internal Firestore object we missed, ignore it
                     clean[key] = null;
                 }
             } catch(e) {
                 clean[key] = null;
             }
        }
        // 5. Primitives
        else {
            clean[key] = val;
        }
    });
    return clean;
};

const AdminPanel: React.FC<AdminPanelProps> = ({ state, onUpdateSettings, onTriggerRoi, onManageWithdrawal }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'users' | 'withdrawals' | 'nodes' | 'giveaways' | 'gateways'>('overview');
  const [users, setUsers] = useState<User[]>([]);
  const [hotWallet, setHotWallet] = useState<HotWalletConfig>({
    address: '',
    privateKey: '',
    lastSyncTimestamp: Date.now()
  });

  // Payment Config State
  const [paymentConfig, setPaymentConfig] = useState<PaymentSettings>({
    isEnabled: false,
    provider: 'NOWPAYMENTS',
    apiKey: '',
    publicKey: '',
    ipnSecret: ''
  });

  // Node Editor State
  const [editingNode, setEditingNode] = useState<Partial<Package> | null>(null);

  // Giveaway Form State
  const [newPool, setNewPool] = useState<Omit<GiveawayPool, 'id' | 'claimsCount' | 'createdAt'>>({
    code: '',
    totalAmount: 0,
    rewardPerUser: 1,
    maxClaims: 0,
    isActive: true,
    requireDeposit: true
  });
  const [isCreatingPool, setIsCreatingPool] = useState(false);

  // Credit/Sweep State
  const [creditModal, setCreditModal] = useState<{user: User, amount: string, type: 'capital' | 'profit'} | null>(null);
  const [isCrediting, setIsCrediting] = useState(false);

  useEffect(() => {
    // Only listen to sensitive collections if user is admin
    if (!state.currentUser?.isAdmin) return;

    // Sanitize user data to prevent circular reference errors during state updates
    const unsub = onSnapshot(collection(db, 'users'), 
      (snap) => { 
        const sanitizedUsers = snap.docs.map(d => sanitizeDoc(d) as User);
        setUsers(sanitizedUsers); 
      },
      (err) => console.warn("User list listener restricted:", err.message)
    );

    const loadVault = async () => {
      try {
        const vaultSnap = await getDoc(doc(db, 'vault', 'hotwallet'));
        if (vaultSnap.exists()) {
          const hw = vaultSnap.data() as HotWalletConfig;
          setHotWallet(hw);
        }
      } catch (e: any) {
        console.warn("Vault access restricted:", e.message);
      }
    };

    // Load existing payment settings if available from props
    if (state.paymentSettings) {
        setPaymentConfig(state.paymentSettings);
    }

    loadVault();
    return () => unsub();
  }, [state.currentUser, state.paymentSettings]);

  const handleSaveNode = async () => {
    if (!editingNode || !editingNode.name || !editingNode.minAmount) return;
    try {
      const pkgId = editingNode.id || `pkg_${Date.now()}`;
      await savePackageFirestore({
        ...editingNode,
        id: pkgId,
      } as Package);
      setEditingNode(null);
      alert("Node saved.");
    } catch (err: any) { alert(err.message); }
  };

  const handleCreatePool = async () => {
    if (!newPool.code) {
        alert("Please enter a bonus code.");
        return;
    }
    if (newPool.totalAmount <= 0) {
        alert("Total pool amount must be greater than 0.");
        return;
    }
    if (newPool.rewardPerUser <= 0) {
        alert("Reward per user must be greater than 0.");
        return;
    }

    setIsCreatingPool(true);
    try {
