// CRITICAL FIX: Bulletproof Sanitizer to prevent Circular JSON errors
// We use duck-typing (checking properties) instead of class names (constructor.name)
// because class names get minified (e.g. 'Sa', 'Q$1') in production builds.
const sanitizeDoc = (docSnap: any) => {
    const data = docSnap.data();
    if (!data) return { id: docSnap.id };

    const clean: any = { id: docSnap.id };

    Object.keys(data).forEach(key => {
        const val = data[key];

        if (!val) {
            clean[key] = val;
            return;
        }

        // 1. Handle Timestamp (convert to millis)
        if (typeof val.toMillis === 'function') {
            clean[key] = val.toMillis();
        }
        // 2. Handle DocumentReference (Robust Duck Typing)
        // If it has .path and .id and they are strings, treat it as a reference and flatten it.
        // We do NOT use constructor.name because it changes during minification.
        else if (typeof val === 'object' && typeof val.path === 'string' && typeof val.id === 'string') {
             clean[key] = val.path;
        }
        // 3. Handle Arrays (recurse gently)
        else if (Array.isArray(val)) {
            clean[key] = val.map((item: any) => {
                if (item && typeof item.toMillis === 'function') return item.toMillis();
                if (item && typeof item.path === 'string' && typeof item.id === 'string') return item.path;
                return item;
            });
        }
        // 4. Handle Objects (Safe plain object copy)
        else if (typeof val === 'object') {
             // Check for internal Firestore properties that indicate a complex object we missed
             if ('firestore' in val || '_key' in val || 'converter' in val) {
                 clean[key] = null; // Discard complex object to prevent circular crash
             } else {
                 try {
                     // Check if it's a plain object or something safe to copy
                     if (Object.prototype.toString.call(val) === '[object Object]') {
                         clean[key] = { ...val };
                     } else {
                         clean[key] = null;
                     }
                 } catch(e) {
                     clean[key] = null;
                 }
             }
        }
        // 5. Primitives
        else {
            clean[key] = val;
        }
    });
    return clean;
};

