    if (!state.currentUser?.isAdmin) return;

    // Sanitize user data to prevent circular reference errors during state updates
    const unsub = onSnapshot(collection(db, 'users'), 
      (snap) => { 
        const sanitizedUsers = snap.docs.map(d => sanitizeDoc(d) as User);
        setUsers(sanitizedUsers); 
      },
      (err) => console.warn("User list listener restricted:", err.message)
    );

    const loadVault = async () => {
      try {
        const vaultSnap = await getDoc(doc(db, 'vault', 'hotwallet'));
        if (vaultSnap.exists()) {
          const hw = vaultSnap.data() as HotWalletConfig;
          setHotWallet(hw);
        }
      } catch (e: any) {
        console.warn("Vault access restricted:", e.message);
      }
    };

    // Load existing payment settings if available from props
    if (state.paymentSettings) {
        setPaymentConfig(state.paymentSettings);
    }

    loadVault();
    return () => unsub();
  }, [state.currentUser, state.paymentSettings]);

  const handleSaveNode = async () => {
    if (!editingNode || !editingNode.name || !editingNode.minAmount) return;
    try {
      const pkgId = editingNode.id || `pkg_${Date.now()}`;
      await savePackageFirestore({
        ...editingNode,
        id: pkgId,
      } as Package);
      setEditingNode(null);
      alert("Node saved.");
    } catch (err: any) { alert(err.message); }
  };

  const handleCreatePool = async () => {
    if (!newPool.code) {
        alert("Please enter a bonus code.");
        return;
    }
    if (newPool.totalAmount <= 0) {
        alert("Total pool amount must be greater than 0.");
        return;
    }
    if (newPool.rewardPerUser <= 0) {
        alert("Reward per user must be greater than 0.");
        return;
    }

    setIsCreatingPool(true);
    try {
      const calculatedMax = Math.floor(newPool.totalAmount / newPool.rewardPerUser);
      await createGiveawayPoolFirestore({ ...newPool, maxClaims: calculatedMax });
      setNewPool({ code: '', totalAmount: 0, rewardPerUser: 1, maxClaims: 0, isActive: true, requireDeposit: true });
