        setWaTaskStatus('IDLE');
    } catch (err: any) {
        alert(err.message);
        // If cooldown error, reset status
        if (err.message.includes('Cooldown')) setWaTaskStatus('IDLE');
    } finally {
        setIsWaTaskProcessing(false);
    }
